func TestBulkCreateSilences_MissingEndsAt(t *testing.T) {
	api := &API{}

	// Create silence without endsAt - use custom JSON
	body := []byte(`[{
		"matchers": [{"name": "alertname", "value": "Test", "isRegex": false}],
