func TestBulkCreateSilences_StartAfterEnd(t *testing.T) {
	api := &API{}

	now := time.Now()
	startsAt := now.Add(2 * time.Hour)
	endsAt := now.Add(1 * time.Hour)

	// Create silence with startsAt after endsAt
	silences := []SilenceDefinition{
		{
			Matchers: []Matcher{
				{
					Name:    "alertname",
					Value:   "Test",
					IsRegex: false,
				},
			},
