	result := api.bulkCreateSilences(req)

	// Verify error
	require.NotNil(t, result.err)
	require.Contains(t, result.err.Error(), "startsAt must be before endsAt")
}

func TestBulkCreateSilences_PartialValidationFailure(t *testing.T) {
	api := &API{}

	// Create array of silences, second one is invalid
	silences := []SilenceDefinition{
		{
			Matchers: []Matcher{
				{
					Name:    "alertname",
					Value:   "TestAlert",
					IsRegex: false,
				},
			},
			EndsAt: time.Now().Add(1 * time.Hour),
		},
		{
			Matchers: []Matcher{}, // Invalid - no matchers
			EndsAt:   time.Now().Add(2 * time.Hour),
		},
	}

	// Marshal to JSON
	body, err := json.Marshal(silences)
	require.NoError(t, err)

	// Create request
	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")

	// Call handler
	result := api.bulkCreateSilences(req)

	// Verify error indicates index of failing silence
	require.NotNil(t, result.err)
	require.Contains(t, result.err.Error(), "silence at index 1")
	require.Contains(t, result.err.Error(), "matchers must not be empty")
}

